    if (!vic_dev) {
        pr_err("Failed to allocate vic device\n");
        return -ENOMEM;  /* Binary returns -1 but -ENOMEM is cleaner */
    }

    /* Binary explicitly zeros the structure */
    memset(vic_dev, 0, sizeof(struct tx_isp_vic_device));

    /* Get subdev pointer */
    sd = &vic_dev->sd;

