{
    uint32_t reg_val;

    pr_info("tisp_s_adr_enable: %s ADR\n", enable ? "Enabling" : "Disabling");

    /* Binary Ninja implementation:
     * int32_t $v0 = system_reg_read(0xc);
     * if (arg1 != 1) {
     *     $a1_1 = $v0 | 0x80;
     *     if (arg1 != 0) return 0xffffffff;
