                        /* Binary Ninja: **(arg1 + 0xb8) = 2; **(arg1 + 0xb8) = 4; while (*$v1_30 != 0) nop; **(arg1 + 0xb8) = 1 */
                        writel(0x2, vic_regs + 0x0);        /* Binary Ninja: Pre-enable state */
